  "flashcards": [
    {
      "front": "le magasin",
      "back": {
        "translation": "der Laden",
        "pronunciation": "[lə ma.ɡa.zɛ̃]",
        "example": "Je vais au magasin.",
        "exampleTranslation": "Ich gehe zum Laden."
      },
      "mnemonic": "„Magasin“ klingt wie „Mama, ich brauche etwas!“, weil man im Laden einkauft.",
      "imagePrompt": "A small shop with a sign that says 'Magasin' and shelves full of everyday items like bread, apples, and milk"
    },
    {
      "front": "l’argent",
      "back": {
        "translation": "das Geld",
        "pronunciation": "[l‿aʁ.ʒɑ̃]",
        "example": "J’ai besoin d’argent.",
        "exampleTranslation": "Ich brauche Geld."
      },
      "mnemonic": "„Argent“ klingt wie „Achtung! Gegen Geld geht es!“, weil man Geld für Dinge bezahlt.",
      "imagePrompt": "A pile of coins and banknotes on a table with the word 'Argent' written in French above it"
    },
    {
      "front": "acheter",
      "back": {
        "translation": "kaufen",
        "pronunciation": "[a.ʃɛ.tər]",
        "example": "Je veux acheter un pain.",
        "exampleTranslation": "Ich möchte ein Brot kaufen."
      },
      "mnemonic": "„Acheter“ klingt wie „A-CHET-TER“, als ob man etwas mit einem Ausrufezeichen holen würde – wie beim Kauf!",
      "imagePrompt": "A person at a counter handing money to a shopkeeper while pointing at bread"
    },
    {
      "front": "payer",
      "back": {
        "translation": "zahlen",
        "pronunciation": "[pa.jɛr]",
        "example": "Je dois payer 5 euros.",
        "exampleTranslation": "Ich muss 5 Euro zahlen."
      },
      "mnemonic": "„Payer“ klingt wie „Pay!“, so wie ein Kassierer sagt: „Zahlen Sie bitte!“",
      "imagePrompt": "A cashier with a cash register and a customer handing over coins"
    },
    {
      "front": "le pain",
      "back": {
        "translation": "das Brot",
        "pronunciation": "[lə pɛ̃]",
        "example": "Le pain est bon.",
        "exampleTranslation": "Das Brot ist gut."
      },
      "mnemonic": "„Pain“ klingt wie „Pfannkuchen“, aber es ist ein Brot – denken Sie an französisches Brot!",
      "imagePrompt": "A fresh loaf of bread on a wooden table with butter being spread"
    },
    {
      "front": "le fromage",
      "back": {
        "translation": "der Käse",
        "pronunciation": "[lə fʁɔ.me]",
        "example": "Je mange du fromage.",
        "exampleTranslation": "Ich esse Käse."
      },
      "mnemonic": "„Fromage“ klingt wie „Froh-Masche“ – ein glücklicher Käse!",
      "imagePrompt": "A piece of yellow cheese on a wooden board with a knife next to it"
    },
    {
      "front": "la pomme",
      "back": {
        "translation": "der Apfel",
        "pronunciation": "[la pɔm]",
        "example": "La pomme est rouge.",
        "exampleTranslation": "Der Apfel ist rot."
      },
      "mnemonic": "„Pomme“ klingt wie „Pommes“, also ein typisches Obst – so wie Pommes Frites, aber frisch!",
      "imagePrompt": "A red apple on a green tree branch with leaves"
    },
    {
      "front": "le fromage blanc",
      "back": {
        "translation": "der Frischkäse",
        "pronunciation": "[lə fʁɔ.me blɑ̃]",
        "example": "Le fromage blanc est doux.",
        "exampleTranslation": "Der Frischkäse ist süß."
      },
      "mnemonic": "„Frais“ bedeutet frisch – der Käse ist also „frischer Käse“, also Frischkäse!",
      "imagePrompt": "A small bowl of white cheese with a spoon next to it, on a kitchen table"
    },
    {
      "front": "le panier",
      "back": {
        "translation": "der Einkaufskorb",
        "pronunciation": "[lə pa.nje]",
        "example": "J’ai mis les pommes dans le panier.",
        "exampleTranslation": "Ich habe die Äpfel in den Korb gelegt."
      },
      "mnemonic": "„Panier“ klingt wie „Panie“, also ein Behältnis zum Einkaufen – wie ein Korb!",
      "imagePrompt": "A wicker shopping basket filled with fruits and vegetables"
    },
    {
      "front": "le prix",
      "back": {
        "translation": "der Preis",
        "pronunciation": "[lə pʁi]",
        "example": "Le prix est élevé.",
        "exampleTranslation": "Der Preis ist hoch."
      },
      "mnemonic": "„Prix“ klingt wie „Preis“, einfach und klar – so wie der Schild im Laden!",
      "imagePrompt": "A price tag on a loaf of bread showing the number 2,50 with a euro symbol"
    }
  ]
}
